func Test_StaleEntityParams_CreateQuery(t *testing.T) {
	tests := []struct {
		name                string
		envValue            string
		expectedLessThanVal string
	}{
		{
			name:                "When env variable is set, should use the environment value",
			envValue:            "5h",
			expectedLessThanVal: "now-5h",
		},
		{
			name:                "When env variable is not set, should use the default value",
			envValue:            "",
			expectedLessThanVal: "now-" + pkg.DefaultStaleDocumentThresholdHours,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			// Setup
			if tt.envValue != "" {
				os.Setenv(pkg.DefaultEntityStalenessThresholdHoursEnv, tt.envValue)
			} else {
				os.Unsetenv(pkg.DefaultEntityStalenessThresholdHoursEnv)
			}
			defer os.Unsetenv(pkg.DefaultEntityStalenessThresholdHoursEnv)

			// Create the params
			params := StaleEntityParams{
				RequiredProperties: []string{constants.UpdatedAt},
				RangeFilters: []map[string]*repository.RangeFieldOperators{
					{
						constants.UpdatedAt: {},
					},
				},
			}

			logContext := log.NewEmptyLogContext(0)
			indexKey := "test-index"
			indexMetadata := &schemaMapping.IndexMetadata{
				KeyProperties: []string{"id"},
			}
			remediationConfig := &schemaMapping.RemediationConfig{}
			searchBatchSize := 100

			// Execute
			queryDetails := params.CreateQuery(
				logContext,
				nil,
				indexKey,
				indexMetadata,
				remediationConfig,
				searchBatchSize,
			)

			// Assert
			queryRequest := queryDetails.Body
			assert.NotNil(t, queryRequest)

			// Verify the LessThan value in the range filter
			rangeFilters := queryRequest.Params.RangeFilters
			assert.NotEmpty(t, rangeFilters)
			updatedAtFilter := rangeFilters[0][constants.UpdatedAt]
			assert.NotNil(t, updatedAtFilter)
			assert.Equal(t, tt.expectedLessThanVal, updatedAtFilter.LessThan)
		})
	}
}

