// deepCompare compares two values for equality, handling maps and slices regardless of order
func deepCompare(want, got any) bool {
    // If both are nil or one is nil
    if want == nil || got == nil {
        return want == got
    }

    wantVal := reflect.ValueOf(want)
    gotVal := reflect.ValueOf(got)

    // If types don't match
    if wantVal.Type() != gotVal.Type() {
        return false
    }

    switch wantVal.Kind() {
    case reflect.Map:
        // Different number of keys
        if wantVal.Len() != gotVal.Len() {
            return false
        }

        // Check each key-value pair
        for _, key := range wantVal.MapKeys() {
            gotItem := gotVal.MapIndex(key)

            // If key doesn't exist in got map
            if !gotItem.IsValid() {
                return false
            }

            // Compare values recursively
            if !deepCompare(wantVal.MapIndex(key).Interface(), gotItem.Interface()) {
                return false
            }
        }
        return true

    case reflect.Slice, reflect.Array:
        // Different length
        if wantVal.Len() != gotVal.Len() {
            return false
        }

        // Special handling for slices of maps (like the args array) where order doesn't matter
        if wantVal.Len() > 0 && wantVal.Index(0).Kind() == reflect.Map {
            // For map slices, we need to check if every item in want exists in got (order independent)
            matches := make([]bool, wantVal.Len()) // Track matched items

            for i := 0; i < wantVal.Len(); i++ {
                wantItem := wantVal.Index(i).Interface()

                // Try to find a match for this want item
                for j := 0; j < gotVal.Len(); j++ {
                    if !matches[j] && deepCompare(wantItem, gotVal.Index(j).Interface()) {
                        matches[j] = true
                        break
                    }
                }

                // If no match found for this item
                if !matches[i] {
                    return false
                }
            }
            return true
        } else {
            // For regular slices, compare elements in order
            for i := 0; i < wantVal.Len(); i++ {
                if !deepCompare(wantVal.Index(i).Interface(), gotVal.Index(i).Interface()) {
                    return false
                }
            }
            return true
        }

    default:
        // For all other types, use regular equality
        return reflect.DeepEqual(want, got)
    }
}
